// Parse Firestore response and filter leads that are due today or overdue
// Also skip leads that already have a pending_email queued

const today = new Date().toISOString().slice(0, 10);

function fsVal(field) {
  if (!field) return null;
  if (field.stringValue  !== undefined) return field.stringValue;
  if (field.integerValue !== undefined) return Number(field.integerValue);
  if (field.doubleValue  !== undefined) return field.doubleValue;
  if (field.booleanValue !== undefined) return field.booleanValue;
  if (field.nullValue    !== undefined) return null;
  if (field.mapValue) {
    const out = {};
    for (const [k, v] of Object.entries(field.mapValue.fields || {})) out[k] = fsVal(v);
    return out;
  }
  if (field.arrayValue) return (field.arrayValue.values || []).map(fsVal);
  return null;
}

function parseDoc(raw) {
  const nameParts = raw.document.name.split('/');
  const id = nameParts[nameParts.length - 1];
  const fields = raw.document.fields || {};
  const lead = { id };
  for (const [k, v] of Object.entries(fields)) lead[k] = fsVal(v);
  return lead;
}

const items = $input.all();
const results = [];

for (const item of items) {
  const body = item.json;
  if (!body || !body.document) continue; // skip empty rows

  const lead = parseDoc(body);

  // Skip if already has a pending email waiting
  if (lead.pending_email) continue;

  // Skip if no next_due_date (not yet started — step 0)
  // Step 0 means never contacted: treat next_due_date = today to fire touch 1
  const dueDate = lead.next_due_date || today;

  if (dueDate > today) continue; // not due yet

  // Must have email to send to
  if (!lead.email) continue;

  // Max 5 touches
  const nextStep = (lead.current_step || 0) + 1;
  if (nextStep > 5) continue;

  results.push({ json: { ...lead, _nextStep: nextStep } });
}

return results;

// Load templates and render the right one for this lead

const TEMPLATES = [
  {
    step: 1,
    subject: 'Flexible warehouse space near the ports — {{unit_sf}} sf available at Cubework Fontana',
    body: 'Hi {{first_name}},\n\nI wanted to reach out about a {{unit_sf}} sf unit we have available at Cubework Fontana ({{location}}). {{importer_line}}\n\nUnit details:\n  Unit: {{unit}}{{dock_line}}\n  Size: {{unit_sf}} sf\n  Rate: {{rate}}\n  Included: {{included_items}}{{alt_line}}\n\nThe easiest next step is a quick 15-minute tour — I can walk you through the space and how it could work for {{company}}. Would this week work?\n\nBest,\nJustin Cho\nBusiness Development — Cubework Fontana'
  },
  {
    step: 2,
    subject: 'Re: Cubework Fontana — {{unit}} still available',
    body: 'Hi {{first_name}},\n\nJust circling back on the unit I mentioned. We still have {{unit}} ({{unit_sf}} sf{{dock_line2}}) available at {{rate}}.{{alt_sentence}}\n\nFlexible terms — month-to-month is an option if you need it. Happy to do a quick 15-minute tour whenever works for you.\n\nBest,\nJustin'
  },
  {
    step: 3,
    subject: "What's included with your space at Cubework Fontana",
    body: 'Hi {{first_name}},\n\nWanted to share why a few tenants chose Cubework over cheaper options:\n\n• {{included_items}} included — no surprise utility bills.\n• {{importer_bullet}}\n• 24/7 access, loading, and security.\n\nStill have {{unit}} at {{rate}} — worth a 15-minute look?\n\nBest,\nJustin'
  },
  {
    step: 4,
    subject: 'Quick question about your space needs — Cubework Fontana',
    body: 'Hi {{first_name}},\n\nQuick question: what would need to be true about a space for it to be worth a tour?\n\nAsking because I want to make sure I\'m not wasting your time — if {{unit}} ({{unit_sf}} sf, {{rate}}) doesn\'t fit what you need right now, I\'d rather know.{{alt_sentence}}\n\nEither way, happy to give you a straight answer on whether we can make it work.\n\nBest,\nJustin'
  },
  {
    step: 5,
    subject: 'Last note — Cubework Fontana space for {{company}}',
    body: "Hi {{first_name}},\n\nI'll keep this short — I've reached out a few times about the {{unit_sf}} sf unit at Cubework Fontana and haven't heard back. Totally fine if the timing isn't right.\n\nI'll leave it here. If things change and you're looking for flexible warehouse space near the ports, feel free to reach back out.\n\nWishing you and {{company}} the best.\n\nJustin Cho\nBusiness Development — Cubework Fontana"
  }
];

const lead = $input.first().json;
const step = lead._nextStep;
const tpl  = TEMPLATES.find(t => t.step === step);
if (!tpl) throw new Error(`No template for step ${step}`);

function merge(str, l) {
  const dock_line  = l.dock ? ', dock-high access' : '';
  const dock_line2 = l.dock ? ', dock-high' : '';
  const alt_line   = l.alt_option ? `\n  Backup option: ${l.alt_option}` : '';
  const alt_sentence = l.alt_option ? ` I also have ${l.alt_option} if the current unit isn't the right size.` : '';
  const importer_line = l.is_importer
    ? 'Given your importing operations, our location near the LA/Long Beach ports makes container freight straightforward — Cubeship handles shipping and customs so you land freight directly with us.'
    : 'We offer flexible terms with no long lease commitment required to get in.';
  const importer_bullet = l.is_importer
    ? 'Cubeship handles container freight, customs, and last-mile from the same location.'
    : 'No long lease to get in — month-to-month so you\'re not locked in.';

  return str
    .replace(/{{first_name}}/g,     l.first_name || l.contact || 'there')
    .replace(/{{company}}/g,         l.company     || '')
    .replace(/{{unit}}/g,            l.unit         || '')
    .replace(/{{unit_sf}}/g,         l.unit_sf      ? l.unit_sf.toLocaleString() : '')
    .replace(/{{rate}}/g,            l.rate         || '')
    .replace(/{{included_items}}/g,  l.included_items || '')
    .replace(/{{location}}/g,        l.location     || 'Fontana, CA')
    .replace(/{{dock_line}}/g,       dock_line)
    .replace(/{{dock_line2}}/g,      dock_line2)
    .replace(/{{alt_line}}/g,        alt_line)
    .replace(/{{alt_sentence}}/g,    alt_sentence)
    .replace(/{{importer_line}}/g,   importer_line)
    .replace(/{{importer_bullet}}/g, importer_bullet);
}

const pending_email = {
  to:          lead.email,
  subject:     merge(tpl.subject, lead),
  body:        merge(tpl.body, lead),
  step,
  drafted_at:  new Date().toISOString()
};

return [{ json: { ...lead, pending_email } }];

// Build Firestore PATCH body for pending_email field
const lead = $input.first().json;
const pe   = lead.pending_email;

function toFsStr(v) { return { stringValue: String(v) }; }
function toFsInt(v) { return { integerValue: String(v) }; }

const patchBody = {
  fields: {
    pending_email: {
      mapValue: {
        fields: {
          to:         toFsStr(pe.to),
          subject:    toFsStr(pe.subject),
          body:       toFsStr(pe.body),
          step:       toFsInt(pe.step),
          drafted_at: toFsStr(pe.drafted_at)
        }
      }
    }
  }
};

return [{ json: { leadId: lead.id, patchBody } }];
